import React from 'react'
import { useState } from 'react'

function App() {
  const [user, setUser] = useState([
    { id: 1, name: 'A' },
    { id: 2, name: 'B' }
  ]);

  let handleChange = () => {
    setUser([{ id: 1, name: 'A' }, { id: 2, name: "Updated" }]);

  };
  return (
    <>
      <div>
        <h3>User List</h3>
        {user.map((e) => (

          <p key={e.id}>User {e.id}:{e.name}</p>

        ))}
        <button onClick={handleChange}>Update User!</button>

      </div>

    </>

  )
}

export default App